"""Office provider orchestrator for DOCX/ODT."""from __future__ import annotationsimport threadingfrom pathlib import Pathfrom xml.etree import ElementTree as ETfrom zipfile import BadZipFilefrom src.modules.file_discovery.models import DiscoveredDocumentfrom ....interfaces import FileExtractProviderfrom ....models import (    CONTENT_TYPE_TEXT,    ExtractConfig,    ExtractedDocument,    ExtractedDocumentContent,    SEMANTIC_TYPE_DOCUMENT_FRAGMENT,    SEMANTIC_TYPE_REQUIRED_DETECTION,    SourceDocument,)from ....services.file_extract_cache import FileExtractCacheServicefrom .docx_extract import extract_docxfrom .image_pipeline import OfficeImagePipelinefrom .odt_extract import extract_odtfrom src.modules.settings_schema.models import SettingFieldSchemaclass OfficeExtractProvider(FileExtractProvider):    """Extract content from office text formats preserving text/image order."""    PROVIDER_CODE: str = "office_extract_provider"    PAGE_IMAGE_FORMAT: str = "jpg"    DEFAULT_MAX_SIZE: int = 1200    ADAPTIVE_IMAGE_SIZE_SUM_THRESHOLD_PX: int = 560    OFFICE_ALGORITHM_SKIP: str = "skip"    OFFICE_ALGORITHM_ADAPTIVE: str = "adaptive"    IMAGES_MODE_IGNORE: str = "ignore"    IMAGES_MODE_VISION_OCR: str = "vision"    DEFAULT_IMAGES_MODE: str = IMAGES_MODE_IGNORE    @staticmethod    def supported_extensions() -> set[str]:        return {".docx", ".odt"}    @classmethod    def project_settings_schema(cls) -> tuple[SettingFieldSchema, ...]:        return (            SettingFieldSchema(                key="algorithm",                type="select",                default=cls.OFFICE_ALGORITHM_ADAPTIVE,                label="algorithm",                description="",                options=(                    (cls.OFFICE_ALGORITHM_SKIP, cls.OFFICE_ALGORITHM_SKIP),                    (cls.OFFICE_ALGORITHM_ADAPTIVE, cls.OFFICE_ALGORITHM_ADAPTIVE),                ),            ),            SettingFieldSchema(                key="images_mode",                type="select",                default=cls.DEFAULT_IMAGES_MODE,                label="images_mode",                description="",                options=(                    (cls.IMAGES_MODE_IGNORE, cls.IMAGES_MODE_IGNORE),                    (cls.IMAGES_MODE_VISION_OCR, cls.IMAGES_MODE_VISION_OCR),                ),            ),            SettingFieldSchema(                key="max_size",                type="int",                default=cls.DEFAULT_MAX_SIZE,                label="max_size",                description="",            ),        )    def extract(        self,        source: SourceDocument,        config: ExtractConfig,        storage: FileExtractCacheService,        document_hash: str,        cancel_event: threading.Event | None = None,    ) -> ExtractedDocument:        content: list[ExtractedDocumentContent] = []        if cancel_event is not None and cancel_event.is_set():            return self._build_document(source, config, document_hash, content)        algorithm = (            config.get_provider_value(self.PROVIDER_CODE, "algorithm", self.OFFICE_ALGORITHM_ADAPTIVE) or ""        ).strip().lower()        if algorithm == self.OFFICE_ALGORITHM_SKIP:            return self._build_document(source, config, document_hash, content)        path = source.path_obj()        ext = source.normalized_extension()        stem = Path(source.filename).stem or "document"        if self._is_temporary_lock_file(path):            return self._build_document(source, config, document_hash, content)        max_size = self._normalize_image_params(config)        include_images = self._include_images(config)        image_semantic = SEMANTIC_TYPE_REQUIRED_DETECTION        pipeline = OfficeImagePipeline(            storage=storage,            stem=stem,            convert_to=self.PAGE_IMAGE_FORMAT,            max_size=max_size,            image_semantic_type=image_semantic,            min_size_sum_px=self.ADAPTIVE_IMAGE_SIZE_SUM_THRESHOLD_PX,        )        if ext == ".docx":            try:                extract_docx(                    path=path,                    storage=storage,                    pipeline=pipeline,                    out=content,                    flush_text=self._flush_text,                    cancel_event=cancel_event,                )            except (BadZipFile, KeyError, ET.ParseError, OSError, ValueError):                pass        elif ext == ".odt":            try:                extract_odt(                    path=path,                    storage=storage,                    pipeline=pipeline,                    out=content,                    flush_text=self._flush_text,                    cancel_event=cancel_event,                )            except (BadZipFile, KeyError, ET.ParseError, OSError, ValueError):                pass        if not include_images:            content = [item for item in content if item.content_type != "image"]        return self._build_document(source, config, document_hash, content)    @staticmethod    def _build_document(        source: SourceDocument,        config: ExtractConfig,        document_hash: str,        content: list[ExtractedDocumentContent],    ) -> ExtractedDocument:        return ExtractedDocument(            source=DiscoveredDocument(                path=str(source.path),                folder=source.folder,                filename=source.filename,                extension=source.normalized_extension(),                mime_type=source.mime_type,                hash=source.file_hash,            ),            config=config,            extract_hash=document_hash,            content=content,        )    @staticmethod    def _is_temporary_lock_file(path: Path) -> bool:        return path.name.lower().startswith("~$")    @staticmethod    def _include_images(config: ExtractConfig) -> bool:        raw = (            config.get_provider_value(OfficeExtractProvider.PROVIDER_CODE, "images_mode", OfficeExtractProvider.DEFAULT_IMAGES_MODE)            or ""        ).strip().lower()        return raw != OfficeExtractProvider.IMAGES_MODE_IGNORE    @staticmethod    def _normalize_image_params(config: ExtractConfig) -> int:        raw_max_size = config.get_provider_value(OfficeExtractProvider.PROVIDER_CODE, "max_size", OfficeExtractProvider.DEFAULT_MAX_SIZE)        try:            max_size = int(raw_max_size)        except (TypeError, ValueError):            max_size = OfficeExtractProvider.DEFAULT_MAX_SIZE        return max(1, max_size)    @staticmethod    def _flush_text(        text_buffer: list[str],        stem: str,        text_index: int,        storage: FileExtractCacheService,        out: list[ExtractedDocumentContent],    ) -> int:        if not text_buffer:            return text_index        text = "".join(text_buffer)        text_buffer.clear()        text_index += 1        item = storage.save_text_content(            text,            filename=f"{stem}_part{text_index}.txt",            content_type=CONTENT_TYPE_TEXT,            semantic_type=SEMANTIC_TYPE_DOCUMENT_FRAGMENT,        )        if item is not None:            out.append(item)        return text_index